{"code": "import json
import ast

# Load the data from files
books_file = locals()['var_functions.query_db:28']
reviews_file = locals()['var_functions.query_db:32']

# Read books data
books_data = []
with open(books_file, 'r') as f:
    content = f.read()
    try:
        books_data = json.loads(content)
    except:
        books_data = ast.literal_eval(content)

# Read reviews data
reviews_data = []
with open(reviews_file, 'r') as f:
    content = f.read()
    try:
        reviews_data = json.loads(content)
    except:
        reviews_data = ast.literal_eval(content)

# Create lookup dictionaries for books
books_dict = {}
for book in books_data:
    book_id_num = book['book_id'].split('_')[1]
    books_dict[book_id_num] = {
        'book_id': book['book_id'],
        'publication_year': int(book['publication_year']),
        'decade': (int(book['publication_year']) // 10) * 10
    }

# Convert reviews data to match normalized keys
for review in reviews_data:
    purchase_id_num = review['purchase_id'].split('_')[1]
    review['purchase_id'] = purchase_id_num

# Group reviews by book
reviews_by_book = {}
for review in reviews_data:
    book_num = review['purchase_id']
    if book_num not in reviews_by_book:
        reviews_by_book[book_num] = []
    reviews_by_book[book_num].append(float(review['rating']))

# Calculate decade statistics
decade_stats = {}
for book_num, reviews in reviews_by_book.items():
    if book_num in books_dict:
        book_info = books_dict[book_num]
        decade = book_info['decade']

        if decade not in decade_stats:
            decade_stats[decade] = {
                'total_ratings': 0,
                'sum_ratings': 0,
                'book_set': set(),
                'avg_rating': 0
            }

        decade_stats[decade]['total_ratings'] += len(reviews)
        decade_stats[decade]['sum_ratings'] += sum(reviews)
        decade_stats[decade]['book_set'].add(book_num)

# Calculate averages
for decade in decade_stats:
    stats = decade_stats[decade]
    stats['avg_rating'] = stats['sum_ratings'] / stats['total_ratings'] if stats['total_ratings'] > 0 else 0
    stats['num_books'] = len(stats['book_set'])

# Filter decades with at least 10 distinct books
filtered_decades = {decade: stats for decade, stats in decade_stats.items() if stats['num_books'] >= 10}

# Find the decade with highest average rating
if filtered_decades:
    best_decade = max(filtered_decades.items(), key=lambda x: x[1]['avg_rating'])
    result = {
        'decade': best_decade[0],
        'decade_label': f"{best_decade[0]}s",
        'avg_rating': best_decade[1]['avg_rating'],
        'num_books': best_decade[1]['num_books'],
        'total_ratings': best_decade[1]['total_ratings']
    }
else:
    result = {'error': 'No decades with at least 10 books found'}

print('__RESULT__:')
print(json.dumps(result))"}

